// Event Handler Function
function handleClick(event) {
 console.log('Button clicked!');
 console.log('Event type:', event.type);
 console.log('Target:', event.target.id);
}

// Register event listener
document.getElementById('myButton').addEventListener('click', handleClick);

// Using arrow function (ES6)
document.getElementById('myButton').addEventListener('click', (event) => {
 alert('Clicked: ' + event.target.innerText);
});

import java.awt.*;
import java.awt.event.*;

public class ButtonDemo extends Frame implements ActionListener {
 private Button btnClick;
 private TextField display;

 public ButtonDemo() {
 setTitle("Event Demo");
 setSize(300, 200);

 display = new TextField(20);
 btnClick = new Button("Click Me");

 // Register event handler
 btnClick.addActionListener(this);

 add(display, BorderLayout.NORTH);
 add(btnClick, BorderLayout.CENTER);
 setVisible(true);
 }

 // Event handler method
 @Override
 public void actionPerformed(ActionEvent e) {
 if (e.getSource() == btnClick) {
 display.setText("Button clicked at: " + new java.util.Date());
 }
 }

 public static void main(String[] args) {
 new ButtonDemo();
 }
}

using System;

public class Publisher {
 // Declare delegate
 public delegate void NotifyEventHandler(object sender, EventArgs e);

 // Declare event using delegate
 public event NotifyEventHandler OnProcessComplete;

 public void Process() {
 Console.WriteLine("Processing...");

 // Raise event
 if (OnProcessComplete != null) {
 OnProcessComplete(this, EventArgs.Empty);
 }
 }
}

public class Subscriber {
 public void HandleProcess(object sender, EventArgs e) {
 Console.WriteLine("Process completed! Notified via event.");
 }
}

// Usage
class Program {
 static void Main() {
 Publisher pub = new Publisher();
 Subscriber sub = new Subscriber();

 // Subscribe to event
 pub.OnProcessComplete += sub.HandleProcess;

 pub.Process();
 }
}
